from flask import Flask, request, jsonify
from pymongo import MongoClient
from bson import ObjectId
import os
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)

# MongoDB connection
client = MongoClient('mongodb://localhost:27017/')
db = client['content_management_system']

# User profile storage
@app.route('/users', methods=['POST'])
def create_user():
    user_data = request.get_json()
    user_data['password'] = generate_password_hash(user_data['password'])
    result = db.users.insert_one(user_data)
    return jsonify({"id": str(result.inserted_id)}), 201

@app.route('/users/<user_id>', methods=['GET'])
def get_user(user_id):
    user = db.users.find_one({"_id": ObjectId(user_id)})
    if user:
        user['_id'] = str(user['_id'])
        return jsonify(user)
    return jsonify({"error": "User not found"}), 404

@app.route('/users/<user_id>', methods=['PUT'])
def update_user(user_id):
    user_data = request.get_json()
    if 'password' in user_data:
        user_data['password'] = generate_password_hash(user_data['password'])
    result = db.users.update_one(
        {"_id": ObjectId(user_id)},
        {"$set": user_data}
    )
    if result.matched_count:
        return jsonify({"message": "User updated"})
    return jsonify({"error": "User not found"}), 404

# Document queries
@app.route('/documents', methods=['POST'])
def create_document():
    doc_data = request.get_json()
    result = db.documents.insert_one(doc_data)
    return jsonify({"id": str(result.inserted_id)}), 201

@app.route('/documents', methods=['GET'])
def get_documents():
    docs = list(db.documents.find())
    for doc in docs:
        doc['_id'] = str(doc['_id'])
    return jsonify(docs)

@app.route('/documents/<doc_id>', methods=['GET'])
def get_document(doc_id):
    doc = db.documents.find_one({"_id": ObjectId(doc_id)})
    if doc:
        doc['_id'] = str(doc['_id'])
        return jsonify(doc)
    return jsonify({"error": "Document not found"}), 404

# Aggregation pipelines
@app.route('/aggregations/user_stats', methods=['GET'])
def user_statistics():
    pipeline = [
        {"$group": {"_id": "$role", "count": {"$sum": 1}}},
        {"$sort": {"count": -1}}
    ]
    result = list(db.users.aggregate(pipeline))
    return jsonify(result)

@app.route('/aggregations/document_stats', methods=['GET'])
def document_statistics():
    pipeline = [
        {"$group": {"_id": "$category", "count": {"$sum": 1}, "avg_length": {"$avg": {"$strLenCP": "$content"}}}},
        {"$sort": {"count": -1}}
    ]
    result = list(db.documents.aggregate(pipeline))
    return jsonify(result)

if __name__ == '__main__':
    app.run(debug=False)